import { cn } from '@/utils/cn';
import { getColor } from '@utils/helper';
import {
  children,
  Component,
  createContext,
  createEffect,
  createMemo,
  createSignal,
  createUniqueId,
  For,
  JSX,
  mergeProps,
  on,
  onCleanup,
  Show,
  useContext,
} from 'solid-js';
import type {
  CollapsibleConfig,
  PanelProps,
  SplitterContextValue,
  SplitterOrientation,
  SplitterProps,
} from './splitter.types';

const SplitterContext = createContext<SplitterContextValue>({ orientation: 'horizontal' });

type PanelRegistration = {
  id: string;
  props: PanelProps;
};

type PanelRegistryContextValue = {
  register: (reg: PanelRegistration) => void;
  unregister: (id: string) => void;
};

const PanelRegistryContext = createContext<PanelRegistryContextValue | null>(null);

function renderIcon(icon: JSX.Element | (() => JSX.Element) | undefined): JSX.Element {
  if (typeof icon === 'function') return (icon as () => JSX.Element)();
  return icon as JSX.Element;
}

const CollapseLeft = () => (
  <svg width="10" height="10" viewBox="0 0 10 10" fill="currentColor">
    <path d="M6 2L3 5l3 3V2z" />
  </svg>
);

const CollapseRight = () => (
  <svg width="10" height="10" viewBox="0 0 10 10" fill="currentColor">
    <path d="M4 2l3 3-3 3V2z" />
  </svg>
);

const CollapseUp = () => (
  <svg width="10" height="10" viewBox="0 0 10 10" fill="currentColor">
    <path d="M2 6l3-3 3 3H2z" />
  </svg>
);

const CollapseDown = () => (
  <svg width="10" height="10" viewBox="0 0 10 10" fill="currentColor">
    <path d="M2 4l3 3 3-3H2z" />
  </svg>
);

function clamp(v: number, min: number, max: number) {
  return Math.min(Math.max(v, min), max);
}

function redistributeSizes(
  sizes: number[],
  draggerIdx: number,
  delta: number,
  panelMetas: PanelRegistration[],
  collapsed: boolean[],
): number[] {
  // Tìm panel visible thực sự ở hai phía của dragger.
  // Bỏ qua các panel đang collapsed vì chúng bị CSS force về 0 và không
  // đóng góp vào tổng width thực tế — redistribute vào chúng sẽ tạo gap.
  let leftIdx = draggerIdx;
  while (leftIdx >= 0 && collapsed[leftIdx]) leftIdx--;

  let rightIdx = draggerIdx + 1;
  while (rightIdx < sizes.length && collapsed[rightIdx]) rightIdx++;

  if (leftIdx < 0 || rightIdx >= sizes.length) return sizes;

  const next = [...sizes];

  const leftMeta = panelMetas[leftIdx]?.props;
  const rightMeta = panelMetas[rightIdx]?.props;

  const leftMin = leftMeta?.min ?? 0;
  const leftMax = leftMeta?.max ?? 100;
  const rightMin = rightMeta?.min ?? 0;
  const rightMax = rightMeta?.max ?? 100;

  const totalAvail = next[leftIdx] + next[rightIdx];

  // Clamp newLeft trong khoảng [leftMin, leftMax] và đảm bảo right có đủ chỗ tối thiểu
  let newLeft = clamp(next[leftIdx] + delta, leftMin, Math.min(leftMax, totalAvail - rightMin));
  let newRight = totalAvail - newLeft;

  // Nếu right vượt quá rightMax, clamp right lại và tính lại left
  if (newRight > rightMax) {
    newRight = rightMax;
    newLeft = totalAvail - newRight;
    if (newLeft < leftMin || newLeft > leftMax) return sizes;
  }

  if (newRight < rightMin) return sizes;

  next[leftIdx] = newLeft;
  next[rightIdx] = newRight;
  return next;
}

export const SplitterPanel: Component<PanelProps> = rawProps => {
  const registry = useContext(PanelRegistryContext);
  const id = createUniqueId();

  if (registry) {
    registry.register({ id, props: rawProps });
    onCleanup(function unregisterPanel() {
      registry.unregister(id);
    });
  }
  return null;
};

type DraggerItemProps = {
  dIdx: number;
  getPanelList: () => PanelRegistration[];
  getCollapsed: () => boolean[];
  getDraggingIdx: () => number | null;
  orientation: () => SplitterOrientation;
  draggerIcon?: JSX.Element | (() => JSX.Element);
  showCollapsibleIcon: () => CollapsibleConfig;
  collapsibleIcon?: {
    collapse?: JSX.Element | (() => JSX.Element);
    expand?: JSX.Element | (() => JSX.Element);
  };
  collapsedControlled: () => boolean;
  class?: SplitterProps['class'];
  onMouseDown: (idx: number, e: MouseEvent) => void;
  onDblClick: (idx: number) => void;
  onCollapse: (panelIdx: number) => void;
};

const DraggerItem: Component<DraggerItemProps> = p => {
  const dIdx = p.dIdx;

  const leftResizable = createMemo(() => p.getPanelList()[dIdx]?.props.resizable !== false);
  const rightResizable = createMemo(() => p.getPanelList()[dIdx + 1]?.props.resizable !== false);
  const canResize = createMemo(() => leftResizable() && rightResizable());
  const isDragging = createMemo(() => p.getDraggingIdx() === dIdx);

  const leftCollapsible = createMemo(() => p.getPanelList()[dIdx]?.props.collapsible ?? false);
  const rightCollapsible = createMemo(() => p.getPanelList()[dIdx + 1]?.props.collapsible ?? false);
  const hasCollapse = createMemo(() => leftCollapsible() || rightCollapsible());

  const isLeftCollapsed = createMemo(() => p.getCollapsed()[dIdx] ?? false);
  const isRightCollapsed = createMemo(() => p.getCollapsed()[dIdx + 1] ?? false);

  const iconAlwaysShow = createMemo(() => p.showCollapsibleIcon() === true);
  const isH = createMemo(() => p.orientation() === 'horizontal');

  const showBtnNext = createMemo(() => {
    if (p.collapsedControlled()) return false;
    const cfg = p.showCollapsibleIcon();
    if (cfg === false) return false;
    if (!hasCollapse()) return false;

    return rightCollapsible() || isLeftCollapsed();
  });

  const showBtnPrevFull = createMemo(() => {
    if (p.collapsedControlled()) return false;
    const cfg = p.showCollapsibleIcon();
    if (cfg === false) return false;
    if (!hasCollapse()) return false;
    return leftCollapsible() || isRightCollapsed();
  });

  return (
    <div
      class={cn('sp06', !canResize() && 'sp07', isDragging() && 'sp08', p.class?.dragger)}
      onMouseDown={e => p.onMouseDown(dIdx, e)}
      onDblClick={() => p.onDblClick(dIdx)}
    >
      <div class={cn('sp15', p.class?.draggerBar)}>
        {p.draggerIcon ? renderIcon(p.draggerIcon) : null}
      </div>

      <Show when={showBtnPrevFull()}>
        <button
          class={cn(
            'sp10',
            'sp11',
            iconAlwaysShow() && 'sp13',

            (isLeftCollapsed() || isRightCollapsed()) && 'sp14',
            p.class?.collapseBtn,
          )}
          title={isLeftCollapsed() || isRightCollapsed() ? 'Expand' : 'Collapse'}
          onClick={e => {
            e.stopPropagation();

            if (isRightCollapsed()) p.onCollapse(dIdx + 1);
            else p.onCollapse(dIdx);
          }}
        >
          {isLeftCollapsed()
            ? renderIcon(
                p.collapsibleIcon?.expand ?? (isH() ? <CollapseRight /> : <CollapseDown />),
              )
            : isRightCollapsed()
              ? renderIcon(p.collapsibleIcon?.expand ?? (isH() ? <CollapseLeft /> : <CollapseUp />))
              : renderIcon(
                  p.collapsibleIcon?.collapse ?? (isH() ? <CollapseLeft /> : <CollapseUp />),
                )}
        </button>
      </Show>

      <Show when={showBtnNext()}>
        <button
          class={cn(
            'sp10',
            'sp12',
            iconAlwaysShow() && 'sp13',

            (isRightCollapsed() || isLeftCollapsed()) && 'sp14',
            p.class?.collapseBtn,
          )}
          title={isRightCollapsed() ? 'Collapse' : 'Expand'}
          onClick={e => {
            e.stopPropagation();

            if (isLeftCollapsed()) p.onCollapse(dIdx);
            else p.onCollapse(dIdx + 1);
          }}
        >
          {isRightCollapsed()
            ? renderIcon(p.collapsibleIcon?.expand ?? (isH() ? <CollapseLeft /> : <CollapseUp />))
            : isLeftCollapsed()
              ? renderIcon(
                  p.collapsibleIcon?.expand ?? (isH() ? <CollapseRight /> : <CollapseDown />),
                )
              : renderIcon(
                  p.collapsibleIcon?.collapse ?? (isH() ? <CollapseRight /> : <CollapseDown />),
                )}
        </button>
      </Show>
    </div>
  );
};

export const Splitter: Component<SplitterProps> & { Panel: Component<PanelProps> } = rawProps => {
  const p = mergeProps(
    {
      orientation: 'horizontal' as SplitterOrientation,
      lazy: false,
      color: 'primary' as const,
    },
    rawProps,
  );

  const orientation = createMemo<SplitterOrientation>(() =>
    p.vertical ? 'vertical' : (p.orientation ?? 'horizontal'),
  );

  const [panelMetas, setPanelMetas] = createSignal<PanelRegistration[]>([]);

  const registry: PanelRegistryContextValue = {
    register(reg) {
      setPanelMetas(prev => {
        const idx = prev.findIndex(r => r.id === reg.id);
        if (idx >= 0) {
          const next = [...prev];
          next[idx] = reg;
          return next;
        }
        return [...prev, reg];
      });
    },
    unregister(id) {
      setPanelMetas(prev => prev.filter(r => r.id !== id));
    },
  };

  const resolvedChildren = children(() => (
    <PanelRegistryContext.Provider value={registry}>{p.children}</PanelRegistryContext.Provider>
  ));

  function initSizes(metas: PanelRegistration[]): number[] {
    const n = metas.length;
    if (n === 0) return [];
    if (p.size && p.size.length === n) return [...p.size];

    const raw = metas.map(m => m.props.size ?? m.props.defaultSize);
    const hasAll = raw.every(v => v !== undefined);
    if (hasAll) {
      const total = raw.reduce((s, v) => s + v!, 0);
      return raw.map(v => (v! / total) * 100);
    }

    const definedTotal = (raw.filter(v => v !== undefined) as number[]).reduce((s, v) => s + v, 0);
    const undefinedCount = raw.filter(v => v === undefined).length;
    const eachUndefined = undefinedCount > 0 ? Math.max(0, 100 - definedTotal) / undefinedCount : 0;
    return raw.map(v => (v !== undefined ? v : eachUndefined));
  }

  const isCollapsedControlled = createMemo(() => Array.isArray(p.collapsed));

  const [sizes, setSizes] = createSignal<number[]>([]);
  const [collapsedInternal, setCollapsedInternal] = createSignal<boolean[]>([]);
  const [draggingIdx, setDraggingIdx] = createSignal<number | null>(null);

  const collapsed = createMemo(() =>
    isCollapsedControlled() ? (p.collapsed as boolean[]) : collapsedInternal(),
  );
  const setCollapsed = (next: boolean[]) => {
    if (!isCollapsedControlled()) setCollapsedInternal(next);
  };

  const [lazyGhostPos, setLazyGhostPos] = createSignal<number | null>(null);

  createEffect(
    on(panelMetas, metas => {
      if (metas.length === 0) return;
      setSizes(initSizes(metas));
      setCollapsedInternal(metas.map(() => false));
    }),
  );

  createEffect(
    on(
      () => p.size,
      controlled => {
        if (!controlled) return;
        if (controlled.length === panelMetas().length) setSizes([...controlled]);
      },
    ),
  );

  let containerRef: HTMLDivElement | undefined;
  let cachedContainerSize = 0;

  createEffect(function observeContainerSize() {
    if (!containerRef) return;
    const isH = orientation() === 'horizontal';
    const observer = new ResizeObserver(entries => {
      const entry = entries[0];
      if (!entry) return;
      cachedContainerSize = isH ? entry.contentRect.width : entry.contentRect.height;
    });
    observer.observe(containerRef);
    onCleanup(function disconnectContainerObserver() {
      observer.disconnect();
    });
  });

  function getContainerSize(): number {
    return cachedContainerSize;
  }

  // Trả về sizes đã normalize: tổng 100% chỉ tính trên panel visible
  function getNormalizedSizes(): number[] {
    const col = collapsed();
    const raw = sizes();
    const visibleTotal = raw.reduce((sum, s, i) => sum + (col[i] ? 0 : s), 0);
    if (visibleTotal === 0) return raw.map(() => 0);
    return raw.map((s, i) => (col[i] ? s : (s / visibleTotal) * 100));
  }

  let dragStartPos = 0;
  let dragStartSizes: number[] = [];
  let dragStartCollapsed: boolean[] = [];

  function onDraggerMouseDown(idx: number, e: MouseEvent) {
    const metas = panelMetas();
    if (metas[idx]?.props.resizable === false) return;
    if (metas[idx + 1]?.props.resizable === false) return;

    e.preventDefault();
    setDraggingIdx(idx);
    dragStartPos = orientation() === 'horizontal' ? e.clientX : e.clientY;
    dragStartSizes = getNormalizedSizes();
    dragStartCollapsed = [...collapsed()];
    p.onResizeStart?.({ sizes: dragStartSizes, index: idx });

    document.addEventListener('mousemove', onMouseMove);
    document.addEventListener('mouseup', onMouseUp);
  }

  function applyNewSizes(newSizes: number[], idx: number) {
    const col = [...collapsed()];
    let changed = false;
    if (col[idx] && newSizes[idx] > 0) {
      col[idx] = false;
      changed = true;
    }
    if (col[idx + 1] && newSizes[idx + 1] > 0) {
      col[idx + 1] = false;
      changed = true;
    }
    if (changed) setCollapsed(col);
    setSizes(newSizes);
  }

  function onMouseMove(e: MouseEvent) {
    const idx = draggingIdx();
    if (idx === null) return;

    const pos = orientation() === 'horizontal' ? e.clientX : e.clientY;
    const containerSize = getContainerSize();
    if (containerSize === 0) return;

    const deltaPct = ((pos - dragStartPos) / containerSize) * 100;
    const newSizes = redistributeSizes(
      dragStartSizes,
      idx,
      deltaPct,
      panelMetas(),
      dragStartCollapsed,
    );

    if (p.lazy) {
      const leftSumPct = newSizes.slice(0, idx + 1).reduce((s, v) => s + v, 0);
      setLazyGhostPos((leftSumPct / 100) * containerSize);
    } else {
      applyNewSizes(newSizes, idx);
      p.onResize?.({ sizes: newSizes, index: idx });
    }
  }

  function onMouseUp(e: MouseEvent) {
    const idx = draggingIdx();
    if (idx === null) return;

    if (p.lazy) {
      const pos = orientation() === 'horizontal' ? e.clientX : e.clientY;
      const containerSize = getContainerSize();
      if (containerSize > 0) {
        const deltaPct = ((pos - dragStartPos) / containerSize) * 100;
        const newSizes = redistributeSizes(
          dragStartSizes,
          idx,
          deltaPct,
          panelMetas(),
          dragStartCollapsed,
        );
        applyNewSizes(newSizes, idx);
        p.onResize?.({ sizes: newSizes, index: idx });
        p.onResizeEnd?.({ sizes: newSizes, index: idx });
      }
      setLazyGhostPos(null);
    } else {
      p.onResizeEnd?.({ sizes: sizes(), index: idx });
    }

    setDraggingIdx(null);
    document.removeEventListener('mousemove', onMouseMove);
    document.removeEventListener('mouseup', onMouseUp);
  }

  onCleanup(function removeDragListeners() {
    document.removeEventListener('mousemove', onMouseMove);
    document.removeEventListener('mouseup', onMouseUp);
  });

  function collapsePanel(panelIdx: number) {
    const metas = panelMetas();
    if (!metas[panelIdx]?.props.collapsible) return;

    const currentCollapsed = collapsed();
    const newCollapsed = [...currentCollapsed];

    if (currentCollapsed[panelIdx]) {
      // Expand: chỉ bỏ collapsed flag — render tự normalize sizes
      newCollapsed[panelIdx] = false;
      setCollapsed(newCollapsed);
      p.onCollapse?.({ sizes: sizes(), collapsed: newCollapsed, index: panelIdx });
    } else {
      // Collapse: chỉ đánh dấu collapsed — render tự normalize sizes
      newCollapsed[panelIdx] = true;
      setCollapsed(newCollapsed);
      p.onCollapse?.({ sizes: sizes(), collapsed: newCollapsed, index: panelIdx });
    }
  }

  const ghostStyle = createMemo<JSX.CSSProperties>(() => {
    const pos = lazyGhostPos();

    if (pos === null) return { display: 'none' };
    return orientation() === 'horizontal'
      ? { display: 'block', left: `${pos}px` }
      : { display: 'block', top: `${pos}px` };
  });

  return (
    <SplitterContext.Provider value={{ orientation: orientation() }}>
      <div class="hidden">{resolvedChildren()}</div>

      <div
        ref={containerRef}
        class={cn(
          'sp01',
          orientation() === 'vertical' ? 'sp02' : 'sp03',
          getColor(p.color),
          p.class?.root,
        )}
      >
        <For each={panelMetas()}>
          {(meta, idx) => {
            const isCollapsed = createMemo(() => collapsed()[idx()] ?? false);

            // Tính normalized size: chia đều 100% cho các panel visible
            const panelStyle = createMemo<JSX.CSSProperties>(() => {
              if (isCollapsed()) return { display: 'none' };

              const col = collapsed();
              const rawSizes = sizes();

              // Tính tổng size của các panel visible
              const visibleTotal = rawSizes.reduce((sum, s, i) => sum + (col[i] ? 0 : s), 0);

              const s = rawSizes[idx()] ?? 0;
              const normalized = visibleTotal > 0 ? (s / visibleTotal) * 100 : 0;

              return orientation() === 'horizontal'
                ? { 'flex-basis': `${normalized}%`, 'min-width': `${meta.props.min ?? 0}%` }
                : { 'flex-basis': `${normalized}%`, 'min-height': `${meta.props.min ?? 0}%` };
            });

            // Dragger sau panel idx() — ẩn chỉ khi cả hai phía đều không có panel visible.
            // Trong controlled mode: ẩn dragger nếu một trong hai panel kề trực tiếp bị ẩn,
            // vì nút collapse/expand đã bị tắt và thanh chỉ còn dùng để resize (vô nghĩa khi
            // một bên không hiển thị).
            const showDragger = createMemo(() => {
              if (idx() >= panelMetas().length - 1) return false;
              const col = collapsed();

              if (isCollapsedControlled()) {
                return !col[idx()] && !(col[idx() + 1] ?? false);
              }

              // Tìm panel visible gần nhất bên trái (bao gồm idx())
              let hasVisibleLeft = false;
              for (let i = idx(); i >= 0; i--) {
                if (!col[i]) {
                  hasVisibleLeft = true;
                  break;
                }
              }
              // Tìm panel visible gần nhất bên phải (idx()+1 trở đi)
              let hasVisibleRight = false;
              for (let i = idx() + 1; i < panelMetas().length; i++) {
                if (!col[i]) {
                  hasVisibleRight = true;
                  break;
                }
              }
              return hasVisibleLeft || hasVisibleRight;
            });

            return (
              <>
                <div
                  class={cn('sp04', isCollapsed() && 'sp05', meta.props.class, p.class?.panel)}
                  style={panelStyle()}
                  data-panel-id={meta.id}
                >
                  {meta.props.children}
                </div>

                <Show when={showDragger()}>
                  <DraggerItem
                    dIdx={idx()}
                    getPanelList={panelMetas}
                    getCollapsed={collapsed}
                    getDraggingIdx={draggingIdx}
                    orientation={orientation}
                    draggerIcon={p.draggerIcon}
                    showCollapsibleIcon={() => p.showCollapsibleIcon ?? 'auto'}
                    collapsibleIcon={p.collapsibleIcon}
                    collapsedControlled={isCollapsedControlled}
                    class={p.class}
                    onMouseDown={onDraggerMouseDown}
                    onDblClick={dIdx => p.onDraggerDoubleClick?.(dIdx, sizes())}
                    onCollapse={collapsePanel}
                  />
                </Show>
              </>
            );
          }}
        </For>

        <Show when={p.lazy}>
          <div class="sp09" style={ghostStyle()} />
        </Show>
      </div>
    </SplitterContext.Provider>
  );
};

Splitter.Panel = SplitterPanel;
